                if q[i] > 1e-9 and q[i] < 1-1e-9:
                    energy += q[i] * np.log(q[i] + 1e-9) + (1-q[i]) * np.log(1-q[i] + 1e-9)

            if abs(prev_f - energy) < self.params['bayesian_inference_x_free_energy_principle_x_sensitivity_analysis___run_inference_tol']:
                break
            prev_f = energy

        return prev_f, q

