        if prompt_feats['length'] > 10 and c_feats['length'] < 2:
             # Very short answers to complex prompts might be incomplete
             if not re.search(r'\b(yes|no|true|false|\d+)\b', c):
                 penalty += 0.1

        return max(0.0, min(1.0, 1.0 - penalty))

