def _hash_to_spectrum(self, text: str) -> np.ndarray:
        """Convert text to a spectral representation using character frequencies as amplitudes."""
        if not text:
            return np.zeros(self.params['fourier_transforms_x_criticality_x_compositionality___hash_to_spectrum_basis_size'])

        # Simple char-to-float mapping
        chars = [ord(c) / 256.0 for c in text]
        spectrum = np.zeros(self.params['fourier_transforms_x_criticality_x_compositionality___hash_to_spectrum_basis_size'])

        # Construct superposition of basis functions
        for i, val in enumerate(chars):
            freq = (i % (self.params['fourier_transforms_x_criticality_x_compositionality___hash_to_spectrum_basis_size'] // 2)) + 1
            phase = val * 2 * np.pi
            # Superposition: Amplitude modulated by char value, frequency by position
            spectrum[freq-1] += np.sin(phase) * val
            if freq < self.params['fourier_transforms_x_criticality_x_compositionality___hash_to_spectrum_basis_size']:
                spectrum[freq] += np.cos(phase) * val

        # Normalize
        norm = np.linalg.norm(spectrum)
        return spectrum / (norm + 1e-9)

