        t = text.lower()
        features = []

        # Define patterns mapped to indices (modulo D to fit vector)
        patterns = [
            (r'\bnot\b|\bno\b|\bnever\b', 0),          # Negation
            (r'\bif\b|\bthen\b|\bunless\b', 1),        # Conditionals
            (r'\bbecause\b|\bleads to\b|\bresults in\b', 2), # Causal
