            (r'\d+(\.\d+)?', 6),                       # Numerics
            (r'\btrue\b|\bfalse\b|\byes\b|\bno\b', 7)  # Boolean literals
        ]

        vec = np.zeros(self.params['sparse_autoencoders_x_mechanism_design_x_type_theory___parse_to_vector_D'])
