def _tokenize(self, text: str) -> List[str]:
        """Simple tokenizer: lower case, split non-alnum, remove stopwords."""
        clean = []
        current = []
        for char in text.lower():
            if char.isalnum():
                current.append(char)
            else:
                if current:
                    clean.append("".join(current))
                    current = []
        if current:
